const inputData = $input.item.json;
const fechaRaw = inputData.fecha.replace(/\//g, '-');
const horaRaw = String(inputData.hora);
const partes = fechaRaw.split('-').map(Number);
let d, m, y;
if (partes[0] > 1000) { [y, m, d] = partes; }
else if (partes[2] > 1000) { [d, m, y] = partes; }
else { [d, m, y] = partes; y += 2000; }
const horaPartes = horaRaw.replace(':', '.').split('.');
const horas = parseInt(horaPartes[0]);
const minutos = parseInt(horaPartes[1] || '0');
const duracion = parseInt(inputData.duracion_min || 30);
const fechaObj = new Date(y, m - 1, d, horas, minutos, 0);
const fechaFin = new Date(fechaObj.getTime() + duracion * 60000);
const pad = n => String(n).padStart(2, '0');
const toISO = (date) => `${date.getFullYear()}-${pad(date.getMonth()+1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}:00-03:00`;
return {
  ...inputData,
  fecha_hora_iso_start: toISO(fechaObj),
  fecha_hora_iso_end: toISO(fechaFin),
  fecha_formateada: `${pad(d)}/${pad(m)}/${y}`,
  hora_formateada: `${pad(horas)}:${pad(minutos)}`
};

const citas = $input.all();
const hayConflicto = citas.length > 0 && citas[0].json && citas[0].json.id !== undefined;
const datos = $('Convertir fecha').first().json;
return {
  ...datos,
  disponible: !hayConflicto,
  mensaje_estado: hayConflicto ? 'OCUPADO' : 'OK',
  citas_en_conflicto: hayConflicto ? citas.map(c => c.json) : []
};

const datos = $('Verificar disponibilidad').first().json;
return {
  status: 'horario_ocupado',
  mensaje_para_agente: `El horario ${datos.hora_formateada} del ${datos.fecha_formateada} ya tiene una cita agendada. Por favor ofrecé un horario alternativo al paciente.`,
  fecha_solicitada: datos.fecha_formateada,
  hora_solicitada: datos.hora_formateada
};
